import springLogo from '..with_Spring_removebg.png';

const UserHeader = () => {
    return(
        <header className="w-full h-20vh bg-sky-400 flex items-start">
            <div className="container mx-auto px-4">
                {/* <span className="w-3"> */}
                    <img src={springLogo} alt="Spring 로고" className="h-12 w-auto"/>
                {/* </span> */}
            </div>

        </header>

    )


}

export default UserHeader;
